<?php $query=trim((string)($_GET['q']??''));?><section class="catalog-head"><span class="eyebrow">Katalog lengkap</span><h1><?=$query?'Hasil untuk “'.e($query).'”':($slug?'Pilihan kategori':'Semua yang Anda cari')?></h1><p><?=count($items)?> produk ditemukan</p><form action="<?=url('/produk')?>"><label class="sr-only" for="product-search">Cari produk</label><input id="product-search" type="search" name="q" value="<?=e($query)?>" placeholder="Cari nama produk..."><button>Cari</button><?php if($query):?><a class="clear-search" href="<?=url('/produk')?>">Hapus pencarian</a><?php endif?></form></section><section class="product-section"><div class="product-grid"><?php foreach($items as $x)require BASE_PATH.'/app/Views/storefront/product-card.php';?></div><?php if(!$items):?><div class="empty-state"><h2>Produk tidak ditemukan</h2><p>Coba kata kunci lain atau lihat seluruh koleksi.</p><a class="button" href="<?=url('/produk')?>">Lihat semua produk</a></div><?php endif?></section>
